import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ---- Edge case: empty items ----
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // ---- Base premiums for main items (single item, newcomer 0 years, no prior contract) ----
  // For a newcomer's first item, first insurance +10% and fee +5G apply.
  // To keep early tests focused on base premiums, the test descriptions below
  // explicitly note when modifiers apply.

  it("single plain sword for newcomer → 100 base + 10 first-insurance + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single plain amulet for newcomer → 60 base + 6 first-insurance + 5 fee = 71 G");
  it.todo("single plain staff for newcomer → 80 base + 8 first-insurance + 5 fee = 93 G");
  it.todo("single plain potion for newcomer → 40 base + 4 first-insurance + 5 fee = 49 G");

  // ---- Components: runes/moonstones, with the 3-alike block discount ----
  it.todo("2 runes → base 50 G (then first-insurance and fee apply)");
  it.todo("3 runes → base 60 G (block applies)");
  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
  it.todo("7 runes → base 175 G (one block of 3 + 4 singles = 60 + 100)");

  // ---- 'Alike' components clarifier ----
  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");

  // ---- Modifier scope on multi-item policies ----
  it.todo("policy with cursed sword + plain amulet → base 160 G + curse 50 G = 210 G before policy-wide modifiers and fee");

  // ---- Modifier thresholds ----
  it.todo("customer with exactly 2 years with MHPCO → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");

  // ---- Integration examples (premium) ----
  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
  it.todo("long-standing customer (3y), second contract, cursed sword (steel, enchantment 7) → premium 160 G");

  // ---- Rounding ----
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up in MHPCO's favor)");

  // ---- Claim processing: standard reimbursement ----
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
  it.todo("damage to rune (insurance value 250 G), damage 200 G → payout 100 G");

  // ---- Enchantment threshold ----
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then 100 G deductible)");

  // ---- Dragon material ----
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full, then deductible)");

  // ---- Enchantment threshold vs dragon material (both apply) ----
  it.todo("dragon-material sword, enchantment 8, damage 1000 G → payout 400 G (50% then deductible)");
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");

  // ---- Deductible per damage event ----
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per damaged item)");

  // ---- Rounding for payout ----
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down in MHPCO's favor)");

  // ---- Multiple items of same type ----
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("policy covers two swords; dragon attack damages both with separate entries → each gets its own deductible");
  it.todo("policy covers one sword but damages array has two sword entries → CLI rejects claim (non-zero exit)");

  // ---- Cap exhaustion ----
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; premium modifiers do not raise the cap)");
  it.todo("policy covers sword + 3 runes (a block) → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword cap 2000 G; first 1500 G claim → payout 1400 G, remainingCap 600 G");
  it.todo("sword cap 2000 G after first claim leaves 600 G; second 1500 G claim → payout 600 G, remainingCap 0 G");

  // ---- Edge cases / error handling ----
  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr, no results on stdout");
  it.todo("claim references damage for item not in policy → CLI exits non-zero, error to stderr");
  it.todo("claim contains damage entry with amount: -200 → CLI exits non-zero, error to stderr");
});

