const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

type Item = { type: string };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: { op: string; items?: Item[] }[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemBase = (item: Item): number => BASE_PREMIUMS[item.type];

const quotePremium = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const policyBase = items.reduce((sum, it) => sum + itemBase(it), 0);
  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items ?? []),
  }));
  return { results };
};

