  it.todo("damage to rune (insurance value 250 G), damage 200 G → payout 100 G");

  // ---- Enchantment threshold ----
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then 100 G deductible)");

  // ---- Dragon material ----
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (dragon full, then deductible)");

