  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero, error to stderr, no results on stdout");
  it.todo("claim references damage for item not in policy → CLI exits non-zero, error to stderr");
  it.todo("claim contains damage entry with amount: -200 → CLI exits non-zero, error to stderr");
});

