const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const BLOCK_SIZE = 3;
const BLOCK_PRICE = 60;

type Item = { type: string };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: { op: string; items?: Item[] }[];
};

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);

const itemBase = (item: Item): number => BASE_PREMIUMS[item.type];

const componentGroupBase = (count: number, perItem: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_PRICE;
  return count * perItem;
};

const policyBase = (items: Item[]): number => {
  const componentCounts = new Map<string, number>();
  let mainTotal = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      mainTotal += itemBase(item);
    }
  }
  let componentTotal = 0;
  for (const [type, count] of componentCounts) {
    componentTotal += componentGroupBase(count, BASE_PREMIUMS[type]);
  }
  return mainTotal + componentTotal;
};

const quotePremium = (items: Item[]): number => {
  const base = policyBase(items);
  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE;
  return Math.ceil(base + firstInsurance + PROCESSING_FEE);
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items ?? []),
  }));
  return { results };
};

